#include "keypad_4x4.h"
#include <Keypad.h>
static const byte ROWS=4,COLS=4;
static char keys[4][4]={{'1','2','3','A'},{'4','5','6','B'},{'7','8','9','C'},{'*','0','#','D'}};
static byte rowPins[4]={13,12,14,27};
static byte colPins[4]={26,25,33,32};
static Keypad kp(makeKeymap(keys),rowPins,colPins,ROWS,COLS);
static char _key=0;static bool _avail=false;
void keypad_setup(){Serial.println("[keypad] OK 4x4");}
void keypad_loop(){char k=kp.getKey();if(k){_key=k;_avail=true;}}
char keypad_get_key(){_avail=false;return _key;}
bool keypad_available(){return _avail;}
